| MCP:YQnf8p | plugins {
| MCP:YQnf8p |     id 'java-library'
| MCP:YQnf8p |     id 'org.springframework.boot' apply(false)
| MCP:YQnf8p |     id 'io.spring.dependency-management'
| MCP:YQnf8p |     id 'io.spring.javaformat' apply(false)
| MCP:YQnf8p |     id 'org.asciidoctor.jvm.convert' apply(false)
| MCP:YQnf8p | }
| MCP:YQnf8p | 
| MCP:YQnf8p | apply from: 'lint.gradle'
| MCP:YQnf8p | 
| MCP:YQnf8p | allprojects {
| MCP:YQnf8p |     group = "${projectGroup}"
| MCP:YQnf8p |     version = "${applicationVersion}"
| MCP:YQnf8p | 
| MCP:YQnf8p |     repositories {
| MCP:YQnf8p |         mavenCentral()
| MCP:YQnf8p |     }
| MCP:YQnf8p | }
| MCP:YQnf8p | 
| MCP:YQnf8p | subprojects {
| MCP:YQnf8p |     apply plugin: 'java-library'
| MCP:YQnf8p |     apply plugin: 'org.springframework.boot'
| MCP:YQnf8p |     apply plugin: 'io.spring.dependency-management'
| MCP:YQnf8p |     apply plugin: 'org.asciidoctor.jvm.convert'
| MCP:YQnf8p |     
| MCP:YQnf8p |     dependencyManagement {
| MCP:YQnf8p |         imports {
| MCP:YQnf8p |             mavenBom "org.springframework.cloud:spring-cloud-dependencies:${springCloudDependenciesVersion}"
| MCP:YQnf8p |         }
| MCP:YQnf8p |     }
| MCP:YQnf8p | 
| MCP:YQnf8p |     dependencies {
| MCP:YQnf8p |         annotationProcessor 'org.springframework.boot:spring-boot-configuration-processor'
| MCP:YQnf8p |         testImplementation 'org.springframework.boot:spring-boot-test'
| MCP:YQnf8p |         testImplementation 'org.junit.jupiter:junit-jupiter-api'
| MCP:YQnf8p |         testImplementation 'org.junit.jupiter:junit-jupiter-engine'
| MCP:YQnf8p |         testRuntimeOnly 'org.junit.platform:junit-platform-launcher'
| MCP:YQnf8p |         testImplementation 'org.assertj:assertj-core'
| MCP:YQnf8p |         testImplementation 'org.mockito:mockito-core'
| MCP:YQnf8p |     }
| MCP:YQnf8p | 
| MCP:YQnf8p |     java {
| MCP:YQnf8p |         toolchain {
| MCP:YQnf8p |             languageVersion = JavaLanguageVersion.of(project.javaVersion)
| MCP:YQnf8p |         }
| MCP:YQnf8p |     }
| MCP:YQnf8p | 
| MCP:YQnf8p |     bootJar.enabled = false
| MCP:YQnf8p |     jar.enabled = true
| MCP:YQnf8p | 
| MCP:YQnf8p |     test {
| MCP:YQnf8p |         useJUnitPlatform {
| MCP:YQnf8p |             excludeTags 'develop', 'restdocs'
| MCP:YQnf8p |         }
| MCP:YQnf8p |     }
| MCP:YQnf8p | 
| MCP:YQnf8p |     testing {
| MCP:YQnf8p |         suites {
| MCP:YQnf8p |             test {
| MCP:YQnf8p |                 targets {
| MCP:YQnf8p |                     unitTest {
| MCP:YQnf8p |                         testTask.configure {
| MCP:YQnf8p |                             group = 'verification'
| MCP:YQnf8p |                             useJUnitPlatform {
| MCP:YQnf8p |                                 excludeTags 'develop', 'context', 'restdocs'
| MCP:YQnf8p |                             }
| MCP:YQnf8p |                         }
| MCP:YQnf8p |                     }
| MCP:YQnf8p | 
| MCP:YQnf8p |                     contextTest {
| MCP:YQnf8p |                         testTask.configure {
| MCP:YQnf8p |                             group = 'verification'
| MCP:YQnf8p |                             useJUnitPlatform {
| MCP:YQnf8p |                                 includeTags 'context'
| MCP:YQnf8p |                             }
| MCP:YQnf8p |                         }
| MCP:YQnf8p |                     }
| MCP:YQnf8p | 
| MCP:YQnf8p |                     restDocsTest {
| MCP:YQnf8p |                         testTask.configure {
| MCP:YQnf8p |                             group = 'verification'
| MCP:YQnf8p |                             useJUnitPlatform {
| MCP:YQnf8p |                                 includeTags 'restdocs'
| MCP:YQnf8p |                             }
| MCP:YQnf8p |                         }
| MCP:YQnf8p |                     }
| MCP:YQnf8p | 
| MCP:YQnf8p |                     developTest {
| MCP:YQnf8p |                         testTask.configure {
| MCP:YQnf8p |                             group = 'verification'
| MCP:YQnf8p |                             useJUnitPlatform {
| MCP:YQnf8p |                                 includeTags 'develop'
| MCP:YQnf8p |                             }
| MCP:YQnf8p |                         }
| MCP:YQnf8p |                     }
| MCP:YQnf8p |                 }
| MCP:YQnf8p |             }
| MCP:YQnf8p |         }
| MCP:YQnf8p |     }
| MCP:YQnf8p | 
| MCP:YQnf8p |     tasks.named('asciidoctor').configure {
| MCP:YQnf8p |         dependsOn restDocsTest
| MCP:YQnf8p |     }
| MCP:YQnf8p | }

| MCP:YQnf8p | dependencies {
| MCP:YQnf8p |     implementation project(':core:core-enum')
| MCP:YQnf8p |     api 'org.springframework.boot:spring-boot-starter-data-jpa'
| MCP:YQnf8p |     runtimeOnly 'com.mysql:mysql-connector-j'
| MCP:YQnf8p |     runtimeOnly 'com.h2database:h2'
| MCP:YQnf8p | }

| MCP:YQnf8p | dependencies {
| MCP:YQnf8p |     implementation 'org.springframework.boot:spring-boot-starter-actuator'
| MCP:YQnf8p |     runtimeOnly 'io.micrometer:micrometer-registry-prometheus'
| MCP:YQnf8p | }

| MCP:YQnf8p | dependencies {
| MCP:YQnf8p |     api 'org.springframework.boot:spring-boot-restdocs'
| MCP:YQnf8p |     api 'org.springframework.restdocs:spring-restdocs-mockmvc'
| MCP:YQnf8p |     compileOnly 'org.junit.jupiter:junit-jupiter-api'
| MCP:YQnf8p | }

| MCP:YQnf8p | dependencies {
| MCP:YQnf8p |     implementation 'org.springframework.boot:spring-boot-starter-opentelemetry'
| MCP:YQnf8p |     implementation "io.sentry:sentry-logback:${property("sentryVersion")}"
| MCP:YQnf8p | }
